export async function loadKernel(require) {
  // ID constants
  const IDS = {
    ATOM: "00000000-0000-0000-0000-000000000000",
    TYPE_DEFINITION: "11111111-0000-0000-0000-000000000000",
    CODE: "22222222-0000-0000-0000-000000000000",
    KERNEL_MODULE: "33333333-0000-0000-0000-000000000000",
    KERNEL_CORE: "33333333-1111-0000-0000-000000000000",
    KERNEL_STORAGE: "33333333-2222-0000-0000-000000000000",
    KERNEL_VIEWPORT: "33333333-3333-0000-0000-000000000000",
    KERNEL_MODULE_SYSTEM: "33333333-4444-0000-0000-000000000000",
    KERNEL_RENDERING_SYSTEM: "33333333-5555-0000-0000-000000000000",
    KERNEL_REPL: "33333333-6666-0000-0000-000000000000",
    KERNEL_SAFE_MODE: "33333333-7777-0000-0000-000000000000",
    KERNEL_STYLES: "33333333-8888-0000-0000-000000000000",
    RENDERER: "44444444-0000-0000-0000-000000000000",
    DEFAULT_RENDERER: "44444444-1111-0000-0000-000000000000",
    EDITOR: "55555555-0000-0000-0000-000000000000",
    DEFAULT_EDITOR: "55555555-1111-0000-0000-000000000000",
    LIBRARY: "66666666-0000-0000-0000-000000000000",
    VIEWPORT_TYPE: "77777777-0000-0000-0000-000000000000",
    VIEWPORT: "88888888-0000-0000-0000-000000000000"
  };

  const { Storage } = await require(IDS.KERNEL_STORAGE);
  const { Viewport } = await require(IDS.KERNEL_VIEWPORT);
  const { ModuleSystem } = await require(IDS.KERNEL_MODULE_SYSTEM);
  const { RenderingSystem } = await require(IDS.KERNEL_RENDERING_SYSTEM);
  const { REPL } = await require(IDS.KERNEL_REPL);
  const { SafeMode } = await require(IDS.KERNEL_SAFE_MODE);

  class Kernel {
    constructor() {
      this.IDS = IDS;
      this.storage = new Storage();
      this.viewport = new Viewport(this.storage);
      this.moduleSystem = new ModuleSystem(this);
      this.rendering = new RenderingSystem(this);
      this.repl = new REPL(this);
      this.safeMode = new SafeMode(this);

      this.currentRoot = null;
      this._safeMode = false;
      this._editingContext = null;

      this.rootElement = document.createElement('div');
      this.rootElement.id = 'app';
      this.rootElement.innerHTML = '<div id="main-view"></div>';
    }

    async boot() {
      await this.storage.initialize();
      await this.ensureSeedItems();
      await this.applyStyles();

      // Check for safe mode
      const params = new URLSearchParams(window.location.search);
      this._safeMode = params.get('safe') === '1';

      if (this._safeMode) {
        this.safeMode.render(this.rootElement.querySelector('#main-view'));
      } else {
        await this.viewport.restore();

        // Add REPL container
        const replContainer = this.repl.createContainer();
        this.rootElement.appendChild(replContainer);

        // Handle keyboard shortcuts
        document.addEventListener('keydown', async (e) => {
          if (e.key === 'Escape') {
            await this.repl.toggle();
          } else if (e.ctrlKey && e.key === '\\') {
            await this.repl.toggle();
          }
        });

        const rootId = await this.getStartingRoot();
        if (rootId) {
          await this.navigateToItem(rootId);
        } else {
          const mainView = this.rootElement.querySelector('#main-view');
          mainView.innerHTML = `
            <div style="padding: 40px; text-align: center;">
              <h1>Hobson</h1>
              <p>Kernel running!</p>
              <p style="color: #666; margin-top: 20px;">Press <kbd>Esc</kbd> or <kbd>Ctrl+\\</kbd> to open REPL</p>
              <p style="font-size: 14px; color: #999; margin-top: 10px;">Or try in console: <code>await kernel.repl.toggle()</code></p>
            </div>
          `;
        }
      }
    }

    async ensureSeedItems() {
      // Check if seeds exist
      try {
        await this.storage.get(IDS.ATOM);
      } catch (e) {
        // Seeds missing - should have been imported via initial-kernel.json
        console.warn('Seed items not found. Please import initial-kernel.json');
      }
    }

    async applyStyles() {
      try {
        const stylesItem = await this.storage.get(IDS.KERNEL_STYLES);
        const style = document.createElement('style');
        style.textContent = stylesItem.content.code;
        document.head.appendChild(style);
      } catch (e) {
        // Fallback to minimal styles
        const style = document.createElement('style');
        style.textContent = `
          * { box-sizing: border-box; }
          html, body { height: 100%; margin: 0; }
          body { font-family: system-ui, sans-serif; padding: 20px; background: #f5f5f5; }
          #app { height: 100%; display: flex; flex-direction: column; }
          #main-view { flex: 1; background: white; border-radius: 8px; padding: 20px; overflow: auto; }
        `;
        document.head.appendChild(style);
      }
    }

    async getStartingRoot() {
      const params = new URLSearchParams(window.location.search);
      const urlRoot = params.get("root");
      if (urlRoot) {
        try {
          await this.storage.get(urlRoot);
          return urlRoot;
        } catch {
          return null;
        }
      }

      if (this.viewport.rootId) {
        return this.viewport.rootId;
      }

      return null;
    }

    async navigateToItem(itemId) {
      this.currentRoot = itemId;
      this.viewport.setRoot(itemId);
      await this.viewport.persist();
      await this.renderRoot(itemId);
    }

    async renderRoot(itemId) {
      if (!itemId) return;

      const mainView = this.rootElement.querySelector('#main-view');
      if (!mainView) return;

      try {
        // Render the viewport item itself (not the root directly)
        // The viewport renderer will create navigation and render the root inside
        const dom = await this.rendering.renderItem(IDS.VIEWPORT);
        mainView.innerHTML = '';
        mainView.appendChild(dom);
      } catch (error) {
        mainView.innerHTML = `
          <div class="render-error">
            <h3>Render Error</h3>
            <pre>${error.message}</pre>
            <pre>${error.stack}</pre>
          </div>
        `;
      }
    }

    // -------------------------------------------------------------------------
    // Editors
    // -------------------------------------------------------------------------

    async getEditors(typeId) {
      // Find all items that are editors (type chain includes EDITOR)
      const allItems = await this.storage.getAll();
      const allEditors = [];
      for (const item of allItems) {
        if (await this.moduleSystem.typeChainIncludes(item.type, IDS.EDITOR)) {
          allEditors.push(item);
        }
      }
      const result = [];
      const seenIds = new Set();

      let currentType = typeId;
      const visited = new Set();

      while (currentType && !visited.has(currentType)) {
        visited.add(currentType);

        // Find all editors for this type
        const editorsForType = allEditors.filter(e => e.content?.for_type === currentType);
        for (const editor of editorsForType) {
          if (!seenIds.has(editor.id)) {
            seenIds.add(editor.id);
            result.push({
              editor,
              forType: currentType,
              inherited: currentType !== typeId
            });
          }
        }

        // Move up the type chain
        if (currentType === IDS.ATOM) {
          break;
        }

        try {
          const typeItem = await this.storage.get(currentType);
          currentType = typeItem.type;
        } catch {
          break;
        }
      }

      return result;
    }

    async getDefaultEditor(typeId) {
      const editors = await this.getEditors(typeId);

      // First look for one marked as is_default
      const defaultMarked = editors.find(e => e.editor.content?.is_default);
      if (defaultMarked) {
        return defaultMarked.editor;
      }

      // Otherwise return the first one (most specific in type chain)
      if (editors.length > 0) {
        return editors[0].editor;
      }

      // No editor found
      return null;
    }

    async editItem(itemId, editorId = null) {
      const item = await this.storage.get(itemId);
      if (!item) {
        throw new Error(`Item not found: ${itemId}`);
      }

      // Get the editor
      let editor;
      if (editorId) {
        editor = await this.storage.get(editorId);
        if (!editor) {
          throw new Error(`Editor not found: ${editorId}`);
        }
      } else {
        editor = await this.getDefaultEditor(item.type);
      }

      // If no editor found, fall back to raw JSON editing
      if (!editor) {
        this.editItemRaw(item.id);
        return;
      }

      // Execute the editor
      // Editors can be declarative (ui_hints) or imperative (code)
      if (editor.content?.code) {
        // Imperative editor - execute the code
        const editorAPI = this.createEditorAPI(item);
        const module = await this.moduleSystem.require(editor.id);
        const domNode = await module.render(item, editorAPI);

        // Display in a modal
        this.showEditorModal(item, domNode);
      } else {
        // Non-code editor - render it (its renderer handles the logic)
        const editorAPI = this.createEditorAPI(item);
        this._editingContext = { item, editorAPI };
        const domNode = await this.rendering.renderItem(editor.id);
        this._editingContext = null;
        this.showEditorModal(item, domNode);
      }
    }

    createEditorAPI(item) {
      const kernel = this;
      const rendererAPI = this.rendering.createRendererAPI(item);

      // Save function - defined separately so saveAndClose can call it
      const save = async (updatedItem) => {
        const merged = {
          ...item,
          ...updatedItem,
          id: item.id, // Prevent ID changes
          modified: Date.now()
        };
        await kernel.storage.set(merged, kernel);
        return merged;
      };

      return {
        ...rendererAPI,

        // Write operations for editors
        save,

        // Close the editor modal
        close: () => {
          kernel.hideEditorModal();
        },

        // Save and close, then refresh the view
        saveAndClose: async (updatedItem) => {
          try {
            await save(updatedItem);
            kernel.hideEditorModal();
            // Refresh the current view to show changes
            const rootId = kernel.viewport.rootId;
            if (rootId) {
              await kernel.renderRoot(rootId);
            }
          } catch (e) {
            console.error("saveAndClose error:", e);
          }
        }
      };
    }

    showEditorModal(item, content) {
      // Remove any existing modal
      this.hideEditorModal();

      const overlay = document.createElement("div");
      overlay.id = "editor-modal-overlay";
      overlay.style.cssText = `
        position: fixed;
        top: 0;
        left: 0;
        right: 0;
        bottom: 0;
        background: rgba(0, 0, 0, 0.5);
        display: flex;
        align-items: center;
        justify-content: center;
        z-index: 10000;
      `;

      const modal = document.createElement("div");
      modal.style.cssText = `
        background: white;
        border-radius: 8px;
        max-width: 90vw;
        max-height: 90vh;
        overflow: auto;
        box-shadow: 0 4px 20px rgba(0, 0, 0, 0.3);
      `;

      // Header with close button
      const header = document.createElement("div");
      header.style.cssText = `
        display: flex;
        justify-content: space-between;
        align-items: center;
        padding: 12px 16px;
        border-bottom: 1px solid #ddd;
        background: #f5f5f5;
        border-radius: 8px 8px 0 0;
      `;

      const title = document.createElement("span");
      title.textContent = `Editing: ${item.name || item.id.slice(0, 8)}`;
      title.style.fontWeight = "bold";

      const closeBtn = document.createElement("button");
      closeBtn.textContent = "×";
      closeBtn.style.cssText = `
        background: none;
        border: none;
        font-size: 24px;
        cursor: pointer;
        padding: 0 8px;
      `;
      closeBtn.onclick = () => this.hideEditorModal();

      header.appendChild(title);
      header.appendChild(closeBtn);

      // Content area
      const contentArea = document.createElement("div");
      contentArea.style.padding = "16px";
      contentArea.appendChild(content);

      modal.appendChild(header);
      modal.appendChild(contentArea);
      overlay.appendChild(modal);

      // Close on overlay click (but not modal click)
      overlay.onclick = (e) => {
        if (e.target === overlay) {
          this.hideEditorModal();
        }
      };

      // Close on Escape
      const escHandler = (e) => {
        if (e.key === "Escape") {
          this.hideEditorModal();
          document.removeEventListener("keydown", escHandler);
        }
      };
      document.addEventListener("keydown", escHandler);

      document.body.appendChild(overlay);
    }

    hideEditorModal() {
      const existing = document.getElementById("editor-modal-overlay");
      if (existing) {
        existing.remove();
      }
    }

    // -------------------------------------------------------------------------
    // Item List and Raw Editor
    // -------------------------------------------------------------------------

    async showItemList() {
      const mainView = this.rootElement.querySelector('#main-view');
      mainView.innerHTML = "";

      const heading = document.createElement("h2");
      heading.textContent = "All Items";
      mainView.appendChild(heading);

      const items = await this.storage.getAll();
      const list = document.createElement("div");
      list.className = "item-list";

      items.sort((a,b) => a.name.localeCompare(b.name));
      for (const item of items) {
        const preview = document.createElement("div");
        preview.className = "item-preview";

        const info = document.createElement("div");
        info.className = "item-info";

        const name = document.createElement("div");
        name.className = "item-name";
        name.textContent = item.name || item.id;
        info.appendChild(name);

        const type = document.createElement("div");
        type.className = "item-type";
        type.textContent = `Type: ${item.type}`;
        info.appendChild(type);

        preview.appendChild(info);

        const actions = document.createElement("div");

        const viewBtn = document.createElement("button");
        viewBtn.textContent = "View";
        viewBtn.onclick = () => this.navigateToItem(item.id);
        actions.appendChild(viewBtn);

        const editBtn = document.createElement("button");
        editBtn.textContent = "Edit";
        editBtn.style.marginLeft = "5px";
        editBtn.onclick = () => this.editItemRaw(item.id);
        actions.appendChild(editBtn);

        // Delete button (but not for seed items)
        const isSeedItem = Object.values(IDS).includes(item.id);
        if (!isSeedItem) {
          const deleteBtn = document.createElement("button");
          deleteBtn.textContent = "Delete";
          deleteBtn.style.marginLeft = "5px";
          deleteBtn.style.color = "#cc0000";
          deleteBtn.onclick = async () => {
            if (confirm(`Delete "${item.name || item.id}"?`)) {
              await this.deleteItem(item.id);
              this.showItemList(); // Refresh the list
            }
          };
          actions.appendChild(deleteBtn);
        }

        preview.appendChild(actions);
        list.appendChild(preview);
      }

      mainView.appendChild(list);
    }

    async editItemRaw(itemId) {
      const item = await this.storage.get(itemId);
      const json = JSON.stringify(item, null, 2);

      // Try inline editing first
      const itemElement = document.querySelector(`[data-item-id="${itemId}"]`);
      const isInline = !!itemElement;

      // Create editor UI
      const container = document.createElement("div");
      container.className = "raw-editor";
      container.style.cssText = isInline
        ? "height: 100%; display: flex; flex-direction: column;"
        : "max-width: 800px; margin: 20px auto; padding: 20px; display: flex; flex-direction: column;";

      const heading = document.createElement("h2");
      heading.textContent = `Editing: ${item.name || item.id}`;
      heading.style.cssText = "margin: 0 0 10px 0; font-size: 16px;";
      container.appendChild(heading);

      const textarea = document.createElement("textarea");
      textarea.id = "raw-json";
      textarea.value = json;
      textarea.style.cssText = "flex: 1; min-height: 300px; font-family: monospace; font-size: 13px; padding: 10px; border: 1px solid #ccc; border-radius: 4px; resize: vertical;";
      container.appendChild(textarea);

      const actions = document.createElement("div");
      actions.className = "actions";
      actions.style.cssText = "display: flex; gap: 10px; margin-top: 10px;";

      const kernel = this;

      const saveBtn = document.createElement("button");
      saveBtn.textContent = "Save";
      saveBtn.style.cssText = "padding: 8px 16px; cursor: pointer;";
      saveBtn.onclick = async () => {
        try {
          const updated = JSON.parse(textarea.value);
          updated.modified = Date.now();
          await kernel.storage.set(updated, kernel);

          // Clear cache if code item
          if (await kernel.isCodeItem(updated)) {
            kernel.moduleSystem.clearCache();
          }

          // Return to previous view
          if (kernel.viewport.rootId) {
            await kernel.renderRoot(kernel.viewport.rootId);
          } else {
            await kernel.showItemList();
          }
        } catch (error) {
          alert(`Error: ${error.message}`);
        }
      };
      actions.appendChild(saveBtn);

      const cancelBtn = document.createElement("button");
      cancelBtn.textContent = "Cancel";
      cancelBtn.style.cssText = "padding: 8px 16px; cursor: pointer;";
      cancelBtn.onclick = async () => {
        // Return to previous view
        if (kernel.viewport.rootId) {
          await kernel.renderRoot(kernel.viewport.rootId);
        } else {
          await kernel.showItemList();
        }
      };
      actions.appendChild(cancelBtn);

      container.appendChild(actions);

      if (isInline) {
        // Inline mode: replace item content
        const originalStyles = itemElement.style.cssText;
        itemElement.innerHTML = "";
        itemElement.style.cssText = originalStyles + " padding: 15px; overflow: auto;";
        itemElement.appendChild(container);
      } else {
        // Full page mode
        const mainView = this.rootElement.querySelector('#main-view');
        mainView.innerHTML = "";
        mainView.appendChild(container);
      }
    }

    // -------------------------------------------------------------------------
    // REPL API
    // -------------------------------------------------------------------------

    createREPLAPI() {
      const kernel = this;

      return {
        // Storage operations
        get: (id) => kernel.storage.get(id),
        set: async (item) => {
          // Save without triggering re-render
          item.modified = Date.now();
          await kernel.storage.set(item, kernel);
          return item.id;
        },
        update: async (item) => {
          // Save and trigger re-render if there's a current root
          item.modified = Date.now();
          await kernel.storage.set(item, kernel);
          if (kernel.currentRoot) {
            await kernel.renderRoot(kernel.currentRoot);
          }
          return item.id;
        },
        delete: (id) => kernel.deleteItem(id),
        query: (filter) => kernel.storage.query(filter),
        getAll: () => kernel.storage.getAll(),

        // Code operations
        require: (name) => kernel.moduleSystem.require(name),

        // Renderer operations
        renderItem: (itemId, rendererId) => kernel.rendering.renderItem(itemId, rendererId),
        getRenderers: (typeId) => kernel.rendering.getRenderers(typeId),
        getDefaultRenderer: (typeId) => kernel.rendering.getDefaultRenderer(typeId),
        findRenderer: (typeId) => kernel.rendering.findRenderer(typeId),

        // Editors
        getEditors: (typeId) => kernel.getEditors(typeId),
        getDefaultEditor: (typeId) => kernel.getDefaultEditor(typeId),
        editItem: (itemId, editorId) => kernel.editItem(itemId, editorId),

        // Parent-child operations
        setChildRenderer: (parentId, childId, rendererId) => kernel.setChildRenderer(parentId, childId, rendererId),
        findParentOf: (childId) => kernel.findParentOf(childId),
        addChild: (parentId, childId) => kernel.addChild(parentId, childId),
        removeChild: (parentId, childId) => kernel.removeChild(parentId, childId),

        // Navigation
        navigate: (id) => kernel.navigateToItem(id),

        // Export
        export: async () => {
          const items = await kernel.storage.getAll();
          const json = JSON.stringify(items, null, 2);
          const blob = new Blob([json], { type: "application/json" });
          const url = URL.createObjectURL(blob);
          const a = document.createElement("a");
          a.href = url;
          a.download = `backup-${Date.now()}.json`;
          a.click();
          URL.revokeObjectURL(url);
          return items.length;
        },

        // Import
        import: async () => {
          return new Promise((resolve, reject) => {
            const input = document.createElement("input");
            input.type = "file";
            input.accept = ".json";
            input.onchange = async (e) => {
              const file = e.target.files[0];
              if (!file) {
                reject(new Error("No file selected"));
                return;
              }

              try {
                const text = await file.text();
                const data = JSON.parse(text);
                const items = Array.isArray(data) ? data : [data];

                let created = 0;
                let updated = 0;
                let skipped = 0;

                for (const item of items) {
                  if (!item.id) {
                    item.id = crypto.randomUUID();
                  }

                  try {
                    const exists = await kernel.storage.exists(item.id);

                    // Ensure timestamps
                    if (!item.created) item.created = Date.now();
                    item.modified = Date.now();

                    await kernel.storage.set(item, kernel);

                    // Clear module cache if it's a code item
                    if (await kernel.isCodeItem(item)) {
                      kernel.moduleSystem.clearCache();
                    }

                    if (exists) {
                      updated++;
                    } else {
                      created++;
                    }
                  } catch (error) {
                    console.warn(`Failed to import item ${item.id}: ${error.message}`);
                    skipped++;
                  }
                }

                resolve({ created, updated, skipped });
              } catch (error) {
                reject(error);
              }
            };
            input.click();
          });
        },

        // Well-known IDs
        IDS,

        // Helper functions
        helpers: {
          findByName: async (name) => {
            const items = await kernel.storage.query({ name });
            return items.length > 0 ? items[0] : null;
          },
          listByType: async (typeId) => {
            return await kernel.storage.query({ type: typeId });
          },
          createType: async (name, description) => {
            const id = crypto.randomUUID();
            await kernel.storage.set({
              id,
              name,
              type: IDS.TYPE_DEFINITION,
              created: Date.now(),
              modified: Date.now(),
              children: [],
              content: { description }
            }, kernel);
            return id;
          }
        },

        // Viewport
        viewport: {
          select: (itemId, parentId) => kernel.viewport.select(itemId, parentId),
          clearSelection: () => kernel.viewport.clearSelection(),
          getSelection: () => kernel.viewport.getSelection(),
          getSelectionParent: () => kernel.viewport.getSelectionParent(),
          getRoot: () => kernel.viewport.rootId,
          getRootRenderer: () => kernel.viewport.getRootRenderer(),
          setRootRenderer: async (rendererId) => {
            kernel.viewport.setRootRenderer(rendererId);
            await kernel.viewport.persist();
          }
        }
      };
    }

    // -------------------------------------------------------------------------
    // Parent-child operations
    // -------------------------------------------------------------------------

    async addChild(parentId, childId) {
      // Validate no cycle
      if (await this.wouldCreateCycle(parentId, childId)) {
        throw new Error(`Adding ${childId} to ${parentId} would create a cycle`);
      }

      const parent = await this.storage.get(parentId);
      if (!parent.children) parent.children = [];

      // Check if child already exists (all children are objects)
      const existingIndex = parent.children.findIndex(c => c.id === childId);

      if (existingIndex >= 0) {
        return; // Already a child
      }

      // Calculate default position (simple diagonal stacking)
      const numChildren = parent.children.length;
      const offset = numChildren * 30; // Stack diagonally

      // Calculate z-index: find max z of unpinned windows and add 1
      const unpinnedChildren = parent.children.filter(c => !c.pinned);
      const maxZ = Math.max(...unpinnedChildren.map(c => c.z || 1000), 999);

      const newChild = {
        id: childId,
        x: 20 + offset,
        y: 20 + offset,
        width: 400,
        height: 300,
        z: maxZ + 1,
        pinned: false
      };

      const updated = {
        ...parent,
        children: [...parent.children, newChild],
        modified: Date.now()
      };

      // Save silently without triggering re-render
      await this.storage.set(updated, this);

      // Return the new child object for manual DOM manipulation
      return newChild;
    }

    async removeChild(parentId, childId) {
      const parent = await this.storage.get(parentId);
      const updated = {
        ...parent,
        children: parent.children.filter(c => c.id !== childId),
        modified: Date.now()
      };
      await this.storage.set(updated, this);
      await this.renderRoot(this.currentRoot);
    }

    async setChildRenderer(parentId, childId, rendererId) {
      const parent = await this.storage.get(parentId);
      const childIndex = parent.children.findIndex(c => c.id === childId);

      if (childIndex < 0) {
        throw new Error(`Child ${childId} not found in parent ${parentId}`);
      }

      // Update the child's renderer
      const updatedChildren = [...parent.children];
      updatedChildren[childIndex] = {
        ...updatedChildren[childIndex],
        renderer: rendererId
      };

      const updated = {
        ...parent,
        children: updatedChildren,
        modified: Date.now()
      };

      await this.storage.set(updated, this);
    }

    async findParentOf(childId) {
      const allItems = await this.storage.getAll();
      for (const item of allItems) {
        if (item.children && item.children.some(c => c.id === childId)) {
          return item;
        }
      }
      return null;
    }

    async wouldCreateCycle(parentId, newChildId) {
      const canReach = async (fromId, toId, visited = new Set()) => {
        if (fromId === toId) return true;
        if (visited.has(fromId)) return false;

        visited.add(fromId);

        try {
          const item = await this.storage.get(fromId);
          for (const child of (item.children || [])) {
            if (await canReach(child.id, toId, visited)) {
              return true;
            }
          }
        } catch {
          // Item doesn't exist
        }

        return false;
      };

      return await canReach(newChildId, parentId);
    }

    async deleteItem(itemId) {
      // Find all parents
      const allItems = await this.storage.getAll();
      const parents = allItems.filter(parentItem => {
        if (!parentItem.children) return false;
        return parentItem.children.some(child => child.id === itemId);
      });

      // Remove from all parents
      for (const parent of parents) {
        await this.removeChild(parent.id, itemId);
      }

      // Delete the item
      await this.storage.delete(itemId);

      // Clear module cache
      this.moduleSystem.clearCache();

      // Re-render if we deleted from current root
      if (parents.some(p => p.id === this.currentRoot)) {
        await this.renderRoot(this.currentRoot);
      }
    }

    async isCodeItem(item) {
      return await this.moduleSystem.isCodeItem(item);
    }

    reloadKernel() {
      window.postMessage({type: 'reload-kernel'}, '*');
    }
  }

  return Kernel;
}

// kernel-storage module
export class Storage {
  constructor() {
    this.db = null;
    this.dbName = "hobson";
    this.storeName = "items";
  }

  async initialize() {
    return new Promise((resolve, reject) => {
      const request = indexedDB.open(this.dbName, 2);

      request.onerror = () => reject(new Error("Failed to open database"));

      request.onsuccess = (event) => {
        this.db = event.target.result;
        resolve();
      };

      request.onupgradeneeded = (event) => {
        const db = event.target.result;

        if (!db.objectStoreNames.contains(this.storeName)) {
          const store = db.createObjectStore(this.storeName, { keyPath: "id" });
          store.createIndex("type", "type", { unique: false });
          store.createIndex("modified", "modified", { unique: false });
          store.createIndex("name", "name", { unique: false });
        }
      };
    });
  }

  async get(id) {
    return new Promise((resolve, reject) => {
      const transaction = this.db.transaction([this.storeName], "readonly");
      const store = transaction.objectStore(this.storeName);
      const request = store.get(id);

      request.onerror = () => reject(new Error(`Failed to get item: ${id}`));
      request.onsuccess = () => {
        if (request.result) {
          resolve(request.result);
        } else {
          reject(new Error(`Item not found: ${id}`));
        }
      };
    });
  }

  async set(item, kernel) {
    // Validation before saving
    await this._validateItem(item, kernel);

    return new Promise((resolve, reject) => {
      const transaction = this.db.transaction([this.storeName], "readwrite");
      const store = transaction.objectStore(this.storeName);
      const request = store.put(item);

      request.onerror = () => reject(new Error(`Failed to save item: ${item.id}`));
      request.onsuccess = () => resolve();
    });
  }

  async delete(id) {
    return new Promise((resolve, reject) => {
      const transaction = this.db.transaction([this.storeName], "readwrite");
      const store = transaction.objectStore(this.storeName);
      const request = store.delete(id);

      request.onerror = () => reject(new Error(`Failed to delete item: ${id}`));
      request.onsuccess = () => resolve();
    });
  }

  async query(filter) {
    const all = await this.getAll();
    return all.filter(item => {
      for (const [key, value] of Object.entries(filter)) {
        if (item[key] !== value) return false;
      }
      return true;
    });
  }

  async getAll() {
    return new Promise((resolve, reject) => {
      const transaction = this.db.transaction([this.storeName], "readonly");
      const store = transaction.objectStore(this.storeName);
      const request = store.getAll();

      request.onerror = () => reject(new Error("Failed to get all items"));
      request.onsuccess = () => resolve(request.result || []);
    });
  }

  async exists(id) {
    try {
      await this.get(id);
      return true;
    } catch {
      return false;
    }
  }

  async _validateItem(item, kernel) {
    const IDS = {
      ATOM: "00000000-0000-0000-0000-000000000000",
      TYPE_DEFINITION: "11111111-0000-0000-0000-000000000000",
      CODE: "22222222-0000-0000-0000-000000000000"
    };

    // 1. Validate type chain (must reach atom, no cycles)
    await this._validateTypeChain(item.type, new Set(), IDS.ATOM);

    // 2. If code item, validate name uniqueness
    if (kernel && await kernel.isCodeItem(item)) {
      if (!item.name) {
        throw new Error(`Code item ${item.id} must have a name`);
      }

      const existing = await this.query({ name: item.name });
      const conflict = existing.find(i => i.id !== item.id);
      if (conflict) {
        throw new Error(`Code item named '${item.name}' already exists (id: ${conflict.id})`);
      }
    }
  }

  async _validateTypeChain(typeId, visited, ATOM_ID) {
    if (visited.has(typeId)) {
      throw new Error(`Circular type chain detected at: ${typeId}`);
    }

    visited.add(typeId);

    // Self-referential atom is valid
    if (typeId === ATOM_ID) {
      return;
    }

    try {
      const typeItem = await this.get(typeId);
      await this._validateTypeChain(typeItem.type, visited, ATOM_ID);
    } catch (error) {
      if (error.message.includes("not found")) {
        throw new Error(`Type chain broken - item '${typeId}' not found`);
      }
      throw error;
    }
  }
}

// kernel-viewport module
export class Viewport {
  constructor(storage) {
    this.storage = storage;
    this.rootId = null;           // Currently viewed root item
    this.rootRendererId = null;   // Renderer override for root (cached)
    this.selectedItemId = null;   // Currently selected item (runtime only)
    this.selectedParentId = null; // Visual parent of selected item (runtime only)

    this.VIEWPORT_ID = "88888888-0000-0000-0000-000000000000";
  }

  // Set the current root item (runtime only - call persist() to save)
  setRoot(itemId) {
    this.rootId = itemId;
    this.selectedItemId = null; // Clear selection when navigating
    this.selectedParentId = null;
  }

  // Get renderer override for current root
  getRootRenderer() {
    return this.rootRendererId;
  }

  // Set renderer override for current root (call persist() to save)
  setRootRenderer(rendererId) {
    this.rootRendererId = rendererId;
  }

  // Select an item (runtime state only, not persisted)
  select(itemId, parentId = null) {
    this.selectedItemId = itemId;
    this.selectedParentId = parentId;
  }

  // Clear selection
  clearSelection() {
    this.selectedItemId = null;
    this.selectedParentId = null;
  }

  // Get the visual parent of the selected item
  getSelectionParent() {
    return this.selectedParentId;
  }

  // Get currently selected item
  getSelection() {
    return this.selectedItemId;
  }

  // Persist current state to viewport item
  async persist() {
    const viewport = await this.storage.get(this.VIEWPORT_ID);
    viewport.children = this.rootId
      ? [{ id: this.rootId, renderer: this.rootRendererId }]
      : [];
    viewport.modified = Date.now();
    await this.storage.set(viewport);
  }

  // Restore state from persisted viewport item
  async restore() {
    const viewport = await this.storage.get(this.VIEWPORT_ID);
    const child = viewport.children[0];
    if (child) {
      this.rootId = child.id;
      this.rootRendererId = child.renderer || null;
    }
  }
}

// kernel-module-system module
export class ModuleSystem {
  constructor(kernel) {
    this.kernel = kernel;
    this.moduleCache = new Map(); // itemId -> { module, timestamp }
  }

  async require(nameOrId, callStack = new Set()) {
    // Resolve name to ID if necessary
    let itemId = nameOrId;

    // Check if it's a name (not a UUID pattern)
    if (!nameOrId.includes("-") || nameOrId.length < 36) {
      const items = await this.kernel.storage.query({ name: nameOrId });
      if (items.length === 0) {
        throw new Error(`Code item not found: ${nameOrId}`);
      }
      itemId = items[0].id;
    }

    // Check for circular dependencies
    if (callStack.has(itemId)) {
      const chain = Array.from(callStack).join(" -> ");
      throw new Error(`Circular dependency detected: ${chain} -> ${itemId}`);
    }

    // Check cache
    const cached = this.moduleCache.get(itemId);
    const item = await this.kernel.storage.get(itemId);

    // Validate cache freshness
    if (cached && cached.timestamp >= item.modified) {
      return cached.module;
    }

    // Re-evaluate
    callStack.add(itemId);
    const module = await this.evaluateCodeItem(item, callStack);
    callStack.delete(itemId);

    // Update cache
    this.moduleCache.set(itemId, {
      module,
      timestamp: item.modified
    });

    return module;
  }

  async evaluateCodeItem(item) {
    if (!item.content?.code) {
      throw new Error(`Item ${item.id} has no code to evaluate`);
    }

    const code = `
      "use strict";
      ${item.content.code}
    `;

    const blob = new Blob([code], { type: "application/javascript" });
    const url = URL.createObjectURL(blob);

    try {
      const module = await import(url);
      return module;
    } catch (error) {
      throw new Error(`Failed to evaluate code item ${item.id} (${item.name}): ${error.message}`);
    } finally {
      URL.revokeObjectURL(url);
    }
  }

  async isCodeItem(item) {
    const CODE_ID = "22222222-0000-0000-0000-000000000000";
    return await this.typeChainIncludes(item.type, CODE_ID);
  }

  async typeChainIncludes(typeId, targetId) {
    const ATOM_ID = "00000000-0000-0000-0000-000000000000";
    let current = typeId;
    const visited = new Set();

    while (current && !visited.has(current)) {
      if (current === targetId) return true;
      visited.add(current);

      if (current === ATOM_ID) break;

      try {
        const typeItem = await this.kernel.storage.get(current);
        current = typeItem.type;
      } catch {
        break;
      }
    }

    return false;
  }

  clearCache() {
    this.moduleCache.clear();
  }
}

// kernel-rendering module
export class RenderingSystem {
  constructor(kernel) {
    this.kernel = kernel;
  }

  async renderItem(itemId, rendererId = null) {
    const IDS = this.kernel.IDS;
    const item = await this.kernel.storage.get(itemId);

    // Use specified renderer or find default for item's type
    let renderer;
    if (rendererId) {
      renderer = await this.kernel.storage.get(rendererId);
    } else {
      renderer = await this.findRenderer(item.type);
    }

    // Load and execute renderer
    try {
      const rendererModule = await this.kernel.moduleSystem.require(renderer.id);
      const api = this.createRendererAPI(item);
      const domNode = await rendererModule.render(item, api);
      return domNode;
    } catch (error) {
      return this.createErrorView(error, itemId);
    }
  }

  async findRenderer(typeId) {
    const IDS = this.kernel.IDS;
    let currentType = typeId;
    const visited = new Set();

    while (currentType && !visited.has(currentType)) {
      visited.add(currentType);

      // Look for a renderer for this type
      const renderers = await this.kernel.storage.query({ type: IDS.RENDERER });
      const renderer = renderers.find(r => r.content?.for_type === currentType);

      if (renderer) {
        return renderer;
      }

      // Move up the type chain
      if (currentType === IDS.ATOM) {
        break;
      }

      try {
        const typeItem = await this.kernel.storage.get(currentType);
        currentType = typeItem.type;
      } catch {
        break;
      }
    }

    // Fall back to default renderer
    return await this.kernel.storage.get(IDS.DEFAULT_RENDERER);
  }

  // Get all renderers for a type (including inherited from type chain)
  async getRenderers(typeId) {
    const IDS = this.kernel.IDS;
    const allRenderers = await this.kernel.storage.query({ type: IDS.RENDERER });
    const result = [];
    const seenTypes = new Set();

    let currentType = typeId;
    const visited = new Set();

    while (currentType && !visited.has(currentType)) {
      visited.add(currentType);

      // Find all renderers for this type
      const renderersForType = allRenderers.filter(r => r.content?.for_type === currentType);
      for (const renderer of renderersForType) {
        if (!seenTypes.has(renderer.id)) {
          seenTypes.add(renderer.id);
          result.push({
            renderer,
            forType: currentType,
            inherited: currentType !== typeId
          });
        }
      }

      // Move up the type chain
      if (currentType === IDS.ATOM) {
        break;
      }

      try {
        const typeItem = await this.kernel.storage.get(currentType);
        currentType = typeItem.type;
      } catch {
        break;
      }
    }

    // Always include default renderer as fallback option
    const defaultRenderer = await this.kernel.storage.get(IDS.DEFAULT_RENDERER);
    if (!seenTypes.has(defaultRenderer.id)) {
      result.push({
        renderer: defaultRenderer,
        forType: IDS.ATOM,
        inherited: true,
        isDefault: true
      });
    }

    return result;
  }

  // Get the default renderer for a type
  async getDefaultRenderer(typeId) {
    const renderers = await this.getRenderers(typeId);
    return renderers.length > 0 ? renderers[0].renderer : null;
  }

  createRendererAPI(containerItem) {
    const kernel = this.kernel;
    const IDS = kernel.IDS;

    const api = {
      // Create DOM elements
      createElement(tag, props = {}, children = []) {
        const element = document.createElement(tag);

        for (const [key, value] of Object.entries(props)) {
          if (key.startsWith("on") && typeof value === "function") {
            const eventName = key.substring(2).toLowerCase();
            element.addEventListener(eventName, value);
          } else if (key === "class") {
            element.className = value;
          } else if (key === "style" && typeof value === "string") {
            element.style.cssText = value;
          } else {
            element.setAttribute(key, value);
          }
        }

        for (const child of children) {
          if (typeof child === "string") {
            element.appendChild(document.createTextNode(child));
          } else if (child instanceof Node) {
            element.appendChild(child);
          } else if (Array.isArray(child)) {
            // Handle array shorthand: [tag, props, children]
            const [childTag, childProps = {}, childChildren = []] = child;
            const childElement = api.createElement(childTag, childProps, childChildren);
            element.appendChild(childElement);
          }
        }

        return element;
      },

      // Query items (read-only)
      query: (filter) => kernel.storage.query(filter),

      // Get single item (read-only)
      get: (itemId) => kernel.storage.get(itemId),

      // Get all items
      getAll: () => kernel.storage.getAll(),

      // Load code module
      require: (nameOrId) => kernel.moduleSystem.require(nameOrId),

      // Render another item (for containers)
      renderItem: (itemId, rendererId) => kernel.rendering.renderItem(itemId, rendererId),

      // Renderer discovery
      getRenderers: (typeId) => kernel.rendering.getRenderers(typeId),
      getDefaultRenderer: (typeId) => kernel.rendering.getDefaultRenderer(typeId),
      findRenderer: (typeId) => kernel.rendering.findRenderer(typeId),

      // Editors
      getEditors: (typeId) => kernel.getEditors(typeId),
      getDefaultEditor: (typeId) => kernel.getDefaultEditor(typeId),
      editItem: (itemId, editorId) => kernel.editItem(itemId, editorId),
      getEditingContext: () => kernel._editingContext,

      // Navigation
      navigate: (itemId) => kernel.navigateToItem(itemId),
      getCurrentRoot: () => kernel.currentRoot,

      // Open item as sibling window in current container
      openSibling: async (itemId) => {
        const currentRoot = kernel.currentRoot;
        if (!currentRoot) {
          throw new Error('No current root container');
        }
        await kernel.addChild(currentRoot, itemId);
        // Trigger re-render to show the new child
        await kernel.renderRoot(currentRoot);
      },

      // Create new item
      create: async (item, addAsChild = false) => {
        const newItem = {
          ...item,
          id: item.id || crypto.randomUUID(),
          created: Date.now(),
          modified: Date.now(),
          children: item.children || []
        };

        await kernel.storage.set(newItem, kernel);

        if (addAsChild) {
          await kernel.addChild(containerItem.id, newItem.id);
        }

        return newItem.id;
      },

      // Simplified child creation
      createChild: async (type, content = {}) => {
        const newItem = {
          type,
          content,
          children: []
        };
        const id = await api.create(newItem, true);
        // Trigger re-render to show the new child (re-render the root, not necessarily this container)
        await kernel.renderRoot(kernel.currentRoot);
        return id;
      },

      // Save without triggering re-render
      set: async (item) => {
        const updated = {
          ...item,
          modified: Date.now()
        };
        await kernel.storage.set(updated, kernel);
        return item.id;
      },

      // Save and trigger re-render
      update: async (item) => {
        const updated = {
          ...item,
          modified: Date.now()
        };
        await kernel.storage.set(updated, kernel);
        await kernel.renderRoot(kernel.currentRoot);
        return item.id;
      },

      // Deprecated: use set() instead
      updateSilent: async (item) => {
        const updated = {
          ...item,
          modified: Date.now()
        };
        await kernel.storage.set(updated, kernel);
        return item.id;
      },

      // Add child to current container
      addChild: async (childId) => {
        await kernel.addChild(containerItem.id, childId);
      },

      // Remove child from current container
      removeChild: async (childId) => {
        await kernel.removeChild(containerItem.id, childId);
      },

      // Set renderer for a child in current container (2 params)
      // or in any container (3 params: parentId, childId, rendererId)
      setChildRenderer: async (childIdOrParentId, rendererIdOrChildId, optionalRendererId) => {
        if (optionalRendererId !== undefined) {
          // 3-parameter version: setChildRenderer(parentId, childId, rendererId)
          await kernel.setChildRenderer(childIdOrParentId, rendererIdOrChildId, optionalRendererId);
        } else {
          // 2-parameter version: setChildRenderer(childId, rendererId)
          await kernel.setChildRenderer(containerItem.id, childIdOrParentId, rendererIdOrChildId);
        }
      },

      // Find parent of an item
      findParentOf: (itemId) => kernel.findParentOf(itemId),

      // Delete item entirely
      delete: async (itemId) => {
        await kernel.deleteItem(itemId);
      },

      // Get the current container item
      getCurrentItem: () => containerItem,

      // Type chain utilities
      typeChainIncludes: (typeId, targetId) => kernel.moduleSystem.typeChainIncludes(typeId, targetId),

      // UI operations
      editRaw: (itemId) => kernel.editItemRaw(itemId),
      showItemList: () => kernel.showItemList(),

      // For script execution - returns REPL API for code evaluation
      createREPLContext: () => kernel.createREPLAPI(),

      // Well-known IDs
      IDS,

      // Helper functions (same as REPL API)
      helpers: {
        findByName: async (name) => {
          const items = await kernel.storage.query({ name });
          return items.length > 0 ? items[0] : null;
        },
        listByType: async (typeId) => {
          return await kernel.storage.query({ type: typeId });
        },
        createType: async (name, description) => {
          const IDS = kernel.IDS;
          const id = crypto.randomUUID();
          await kernel.storage.set({
            id,
            name,
            type: IDS.TYPE_DEFINITION,
            created: Date.now(),
            modified: Date.now(),
            children: [],
            content: { description }
          }, kernel);
          return id;
        }
      },

      // Viewport API for view state management
      viewport: {
        select: (itemId, parentId) => kernel.viewport.select(itemId, parentId),
        clearSelection: () => kernel.viewport.clearSelection(),
        getSelection: () => kernel.viewport.getSelection(),
        getSelectionParent: () => kernel.viewport.getSelectionParent(),
        getRoot: () => kernel.viewport.rootId,
        getRootRenderer: () => kernel.viewport.getRootRenderer(),
        setRootRenderer: async (rendererId) => {
          kernel.viewport.setRootRenderer(rendererId);
          await kernel.viewport.persist();
        }
      }
    };

    return api;
  }

  createErrorView(error, itemId) {
    const container = document.createElement("div");
    container.className = "render-error";

    const heading = document.createElement("h3");
    heading.textContent = `Error rendering: ${itemId}`;
    container.appendChild(heading);

    const message = document.createElement("pre");
    message.textContent = error.message;
    container.appendChild(message);

    const stack = document.createElement("pre");
    stack.textContent = error.stack || "(no stack trace)";
    container.appendChild(stack);

    const editBtn = document.createElement("button");
    editBtn.textContent = "Edit Item";
    editBtn.onclick = () => this.kernel.editItemRaw(itemId);
    container.appendChild(editBtn);

    return container;
  }
}

// kernel-repl module
export class REPL {
  constructor(kernel) {
    this.kernel = kernel;
    this.history = [];
    this.historyIndex = 0;
    this.containerElement = null;
  }

  createContainer() {
    const container = document.createElement("div");
    container.id = "repl-container";

    // Header with controls
    const header = document.createElement("div");
    header.className = "repl-header";

    const heading = document.createElement("h3");
    heading.textContent = "REPL";
    header.appendChild(heading);

    const statusMsg = document.createElement("div");
    statusMsg.id = "repl-status-message";
    statusMsg.style.cssText = "flex: 1; margin: 0 15px; font-size: 12px; color: #f80; display: none;";
    header.appendChild(statusMsg);

    const controls = document.createElement("div");
    controls.className = "repl-controls";

    const closeBtn = document.createElement("button");
    closeBtn.textContent = "Close";
    closeBtn.onclick = async () => await this.toggle();
    controls.appendChild(closeBtn);

    header.appendChild(controls);
    container.appendChild(header);

    // Input panel (top half)
    const inputPanel = document.createElement("div");
    inputPanel.className = "repl-input-panel";

    const inputScroll = document.createElement("div");
    inputScroll.className = "repl-input-scroll";

    // Input area
    const input = document.createElement("textarea");
    input.id = "repl-input";
    input.placeholder = "Enter JavaScript... (api object is available)\nUse 'return' to see expression values\n\nCtrl+Enter to run | Escape to close | Up/Down for history";
    input.spellcheck = false;
    inputScroll.appendChild(input);
    inputPanel.appendChild(inputScroll);

    // Action buttons
    const actions = document.createElement("div");
    actions.className = "repl-actions";

    const runBtn = document.createElement("button");
    runBtn.textContent = "Run";
    runBtn.className = "primary";
    runBtn.onclick = () => this.run();
    actions.appendChild(runBtn);

    const clearInputBtn = document.createElement("button");
    clearInputBtn.textContent = "Clear";
    clearInputBtn.onclick = () => { input.value = ""; };
    actions.appendChild(clearInputBtn);

    const hint = document.createElement("span");
    hint.className = "repl-hint";
    hint.textContent = "Ctrl+Enter to run | Up/Down for history";
    actions.appendChild(hint);

    inputPanel.appendChild(actions);
    container.appendChild(inputPanel);

    // Splitter
    const splitter = document.createElement("div");
    splitter.className = "repl-splitter";
    container.appendChild(splitter);

    // Transcript panel (bottom half)
    const transcriptPanel = document.createElement("div");
    transcriptPanel.className = "repl-transcript-panel";

    const transcript = document.createElement("div");
    transcript.id = "repl-transcript";

    const transcriptHeader = document.createElement("div");
    transcriptHeader.className = "repl-transcript-header";

    const transcriptHeading = document.createElement("h4");
    transcriptHeading.textContent = "Transcript";
    transcriptHeader.appendChild(transcriptHeading);

    const clearTranscriptBtn = document.createElement("button");
    clearTranscriptBtn.textContent = "Clear Transcript";
    clearTranscriptBtn.onclick = () => {
      document.getElementById("repl-transcript-entries").innerHTML = "";
    };
    transcriptHeader.appendChild(clearTranscriptBtn);

    transcript.appendChild(transcriptHeader);

    const transcriptEntries = document.createElement("div");
    transcriptEntries.id = "repl-transcript-entries";
    transcript.appendChild(transcriptEntries);

    transcriptPanel.appendChild(transcript);
    container.appendChild(transcriptPanel);

    // Add splitter drag functionality
    let isDragging = false;
    let startY = 0;
    let startInputHeight = 0;

    splitter.addEventListener("mousedown", (e) => {
      isDragging = true;
      startY = e.clientY;
      startInputHeight = inputPanel.offsetHeight;
      document.body.style.cursor = "row-resize";
      document.body.style.userSelect = "none";
      e.preventDefault();
    });

    document.addEventListener("mousemove", (e) => {
      if (!isDragging) return;

      const delta = e.clientY - startY;
      const newInputHeight = startInputHeight + delta;
      const containerHeight = container.offsetHeight;
      const headerHeight = header.offsetHeight;
      const splitterHeight = 6;

      const minHeight = 100;
      const maxHeight = containerHeight - headerHeight - splitterHeight - 100;

      if (newInputHeight >= minHeight && newInputHeight <= maxHeight) {
        inputPanel.style.flex = "none";
        inputPanel.style.height = newInputHeight + "px";
        transcriptPanel.style.flex = "1";
      }
    });

    document.addEventListener("mouseup", () => {
      if (isDragging) {
        isDragging = false;
        document.body.style.cursor = "";
        document.body.style.userSelect = "";
      }
    });

    // Keyboard shortcuts
    input.addEventListener("keydown", (e) => {
      // Ctrl+Enter to run
      if (e.ctrlKey && e.key === "Enter") {
        e.preventDefault();
        this.run();
      }

      // Tab for indentation
      if (e.key === "Tab") {
        e.preventDefault();
        const start = input.selectionStart;
        const end = input.selectionEnd;
        input.value = input.value.substring(0, start) + "  " + input.value.substring(end);
        input.selectionStart = input.selectionEnd = start + 2;
      }

      // Up/Down for history
      if (e.key === "ArrowUp" && !e.shiftKey && !e.ctrlKey) {
        if (this.historyIndex > 0) {
          this.historyIndex--;
          input.value = this.history[this.historyIndex];
          e.preventDefault();
          setTimeout(() => {
            input.selectionStart = input.selectionEnd = input.value.length;
          }, 0);
        }
      }

      if (e.key === "ArrowDown" && !e.shiftKey && !e.ctrlKey) {
        if (this.historyIndex < this.history.length - 1) {
          this.historyIndex++;
          input.value = this.history[this.historyIndex];
          e.preventDefault();
        } else if (this.historyIndex === this.history.length - 1) {
          this.historyIndex++;
          input.value = "";
          e.preventDefault();
        }
      }
    });

    this.containerElement = container;
    return container;
  }

  addTranscriptEntry(code, result, error) {
    const container = document.getElementById("repl-transcript-entries");
    if (!container) return;

    const entry = document.createElement("div");
    entry.className = "repl-entry" + (error ? " error" : " success");

    const codeDiv = document.createElement("div");
    codeDiv.className = "repl-entry-code";
    codeDiv.textContent = "> " + code;
    entry.appendChild(codeDiv);

    const outputDiv = document.createElement("div");
    outputDiv.className = error ? "repl-entry-error" : "repl-entry-output";
    outputDiv.textContent = error || result;
    entry.appendChild(outputDiv);

    container.appendChild(entry);

    // Scroll to bottom
    entry.scrollIntoView({ behavior: "smooth", block: "nearest" });
  }

  async run() {
    const input = document.getElementById("repl-input");
    if (!input) return;

    const code = input.value.trim();
    if (!code) return;

    // Add to history
    if (this.history.length === 0 || this.history[this.history.length - 1] !== code) {
      this.history.push(code);
      if (this.history.length > 50) {
        this.history.shift();
      }
    }
    this.historyIndex = this.history.length;

    const api = this.createAPI();

    try {
      // Wrap in async function to allow await
      const asyncFn = new Function("api", `
        return (async () => {
          ${code}
        })();
      `);

      const result = await asyncFn(api);

      let resultStr;
      if (result === undefined) {
        resultStr = "// Executed successfully (no return value)";
      } else if (typeof result === 'string' && result.includes('\n')) {
        resultStr = result;
      } else {
        resultStr = JSON.stringify(result, null, 2);
      }

      this.addTranscriptEntry(code, resultStr, null);
      input.value = "";

    } catch (error) {
      const errorStr = `Error: ${error.message}\n${error.stack}`;
      this.addTranscriptEntry(code, null, errorStr);
    }
  }

  async toggle() {
    const repl = document.getElementById("repl-container");
    const mainView = document.getElementById("main-view");
    if (!repl || !mainView) return;

    const isVisible = repl.classList.contains("visible");
    if (isVisible) {
      // Hide REPL, show main view
      repl.classList.remove("visible");
      mainView.classList.remove("repl-active");
    } else {
      // Show REPL, hide main view
      repl.classList.add("visible");
      mainView.classList.add("repl-active");

      // Focus the input
      const input = document.getElementById("repl-input");
      if (input) input.focus();
    }
  }

  createAPI() {
    const kernel = this.kernel;
    const IDS = kernel.IDS;

    return {
      // Storage operations
      get: (id) => kernel.storage.get(id),
      set: async (item) => {
        item.modified = Date.now();
        await kernel.storage.set(item, kernel);
        return item.id;
      },
      update: async (item) => {
        item.modified = Date.now();
        await kernel.storage.set(item, kernel);
        if (kernel.currentRoot) {
          await kernel.renderRoot(kernel.currentRoot);
        }
        return item.id;
      },
      delete: (id) => kernel.deleteItem(id),
      query: (filter) => kernel.storage.query(filter),
      getAll: () => kernel.storage.getAll(),

      // Code operations
      require: (name) => kernel.moduleSystem.require(name),

      // Renderer operations
      renderItem: (itemId, rendererId) => kernel.rendering.renderItem(itemId, rendererId),
      getRenderers: (typeId) => kernel.rendering.getRenderers(typeId),
      getDefaultRenderer: (typeId) => kernel.rendering.getDefaultRenderer(typeId),
      findRenderer: (typeId) => kernel.rendering.findRenderer(typeId),

      // Parent-child operations
      setChildRenderer: (parentId, childId, rendererId) => kernel.setChildRenderer(parentId, childId, rendererId),
      addChild: (parentId, childId) => kernel.addChild(parentId, childId),
      removeChild: (parentId, childId) => kernel.removeChild(parentId, childId),

      // Navigation
      navigate: (id) => kernel.navigateToItem(id),

      // Export
      export: async () => {
        const items = await kernel.storage.getAll();
        const json = JSON.stringify(items, null, 2);
        const blob = new Blob([json], { type: "application/json" });
        const url = URL.createObjectURL(blob);
        const a = document.createElement("a");
        a.href = url;
        a.download = `backup-${Date.now()}.json`;
        a.click();
        URL.revokeObjectURL(url);
        return items.length;
      },

      // Import
      import: async () => {
        return new Promise((resolve, reject) => {
          const input = document.createElement("input");
          input.type = "file";
          input.accept = ".json";
          input.onchange = async (e) => {
            const file = e.target.files[0];
            if (!file) {
              reject(new Error("No file selected"));
              return;
            }

            try {
              const text = await file.text();
              const data = JSON.parse(text);
              const items = Array.isArray(data) ? data : [data];

              let created = 0;
              let updated = 0;
              let skipped = 0;

              for (const item of items) {
                if (!item.id) {
                  item.id = crypto.randomUUID();
                }

                try {
                  const exists = await kernel.storage.exists(item.id);

                  if (!item.created) item.created = Date.now();
                  item.modified = Date.now();

                  await kernel.storage.set(item, kernel);

                  // Clear module cache if it's a code item
                  if (await kernel.isCodeItem(item)) {
                    kernel.moduleSystem.clearCache();
                  }

                  if (exists) {
                    updated++;
                  } else {
                    created++;
                  }
                } catch (error) {
                  console.warn(`Failed to import item ${item.id}: ${error.message}`);
                  skipped++;
                }
              }

              resolve({ created, updated, skipped });
            } catch (error) {
              reject(error);
            }
          };
          input.click();
        });
      },

      // Reset
      reset: async () => {
        if (!confirm("This will delete ALL data. Are you sure?")) {
          return { cancelled: true };
        }

        const items = await kernel.storage.getAll();
        for (const item of items) {
          await kernel.storage.delete(item.id);
        }

        await kernel.ensureSeedItems();
        window.location.reload();
      },

      // Utilities
      uuid: () => crypto.randomUUID(),
      now: () => Date.now(),

      // Helper functions
      helpers: {
        createType: async (name, description) => {
          const id = crypto.randomUUID();
          await kernel.storage.set({
            id,
            name,
            type: IDS.TYPE_DEFINITION,
            created: Date.now(),
            modified: Date.now(),
            children: [],
            content: { description }
          }, kernel);
          return id;
        },

        createRenderer: async (name, forType, code) => {
          const id = crypto.randomUUID();
          await kernel.storage.set({
            id,
            name,
            type: IDS.RENDERER,
            created: Date.now(),
            modified: Date.now(),
            children: [],
            content: { for_type: forType, code }
          }, kernel);
          return id;
        },

        createLibrary: async (name, code) => {
          const id = crypto.randomUUID();
          await kernel.storage.set({
            id,
            name,
            type: IDS.LIBRARY,
            created: Date.now(),
            modified: Date.now(),
            children: [],
            content: { code }
          }, kernel);
          return id;
        },

        duplicateItem: async (id, newName) => {
          const original = await kernel.storage.get(id);
          const duplicate = {
            ...original,
            id: crypto.randomUUID(),
            name: newName || (original.name ? original.name + "_copy" : undefined),
            created: Date.now(),
            modified: Date.now()
          };
          await kernel.storage.set(duplicate, kernel);
          return duplicate.id;
        },

        findByName: async (name) => {
          const items = await kernel.storage.query({ name });
          return items.length > 0 ? items[0] : null;
        },

        listByType: async (typeId) => {
          return await kernel.storage.query({ type: typeId });
        },

        listTypes: async () => {
          return await kernel.storage.query({ type: IDS.TYPE_DEFINITION });
        },

        listRenderers: async () => {
          return await kernel.storage.query({ type: IDS.RENDERER });
        },

        listCode: async () => {
          const all = await kernel.storage.getAll();
          const codeItems = [];
          for (const item of all) {
            if (await kernel.isCodeItem(item)) {
              codeItems.push(item);
            }
          }
          return codeItems;
        }
      },

      // Viewport
      viewport: {
        select: (itemId, parentId) => kernel.viewport.select(itemId, parentId),
        clearSelection: () => kernel.viewport.clearSelection(),
        getSelection: () => kernel.viewport.getSelection(),
        getSelectionParent: () => kernel.viewport.getSelectionParent(),
        getRoot: () => kernel.viewport.rootId,
        getRootRenderer: () => kernel.viewport.getRootRenderer(),
        setRootRenderer: async (rendererId) => {
          kernel.viewport.setRootRenderer(rendererId);
          await kernel.viewport.persist();
        }
      },

      // Well-known IDs
      IDS,

      // Help
      help: (method) => {
        // Return help text
        return "REPL API - See documentation for details";
      }
    };
  }
}

// kernel-safe-mode module
export class SafeMode {
  constructor(kernel) {
    this.kernel = kernel;
  }

  render(rootElement) {
    rootElement.innerHTML = `
      <div id="safe-mode">
        <h1>⚠️ Safe Mode</h1>
        <p>Booted with minimal kernel only. No user code items loaded.</p>
        <p>Use this mode to fix broken code items.</p>
        <p style="color: #666; font-size: 12px;">Access safe mode anytime by adding <code>?safe=1</code> to the URL.</p>

        <div class="actions">
          <button onclick="kernel.safeMode.listAllItems()">View All Items</button>
          <button onclick="kernel.safeMode.listCodeItems()">View Code Items Only</button>
          <button onclick="kernel.safeMode.exportData()">Export All Data</button>
          <button onclick="kernel.safeMode.importData()">Import Data</button>
          <button onclick="kernel.safeMode.resetSystem()">Reset System (Dangerous!)</button>
          <button onclick="window.location.href = window.location.pathname">Exit Safe Mode</button>
        </div>

        <div id="item-list" class="item-list"></div>
      </div>
    `;
  }

  async listAllItems() {
    const items = await this.kernel.storage.getAll();
    this._renderItemList(items, "All Items");
  }

  async listCodeItems() {
    const items = await this.kernel.storage.getAll();
    const codeItems = [];

    for (const item of items) {
      if (await this.kernel.isCodeItem(item)) {
        codeItems.push(item);
      }
    }

    this._renderItemList(codeItems, "Code Items");
  }

  _renderItemList(items, title) {
    const listEl = document.getElementById("item-list");
    if (!listEl) return;

    listEl.innerHTML = `<h2>${title} (${items.length})</h2>`;

    for (const item of items) {
      const preview = document.createElement("div");
      preview.className = "item-preview";
      preview.innerHTML = `
        <div class="item-info">
          <div class="item-name">${this._escapeHtml(item.name || item.id)}</div>
          <div class="item-type">Type: ${item.type}</div>
        </div>
        <div>
          <button onclick="kernel.safeMode.editItem('${item.id}')">Edit as JSON</button>
          <button onclick="kernel.safeMode.deleteItem('${item.id}')" style="color: red;">Delete</button>
        </div>
      `;
      listEl.appendChild(preview);
    }
  }

  async editItem(itemId) {
    const item = await this.kernel.storage.get(itemId);
    const json = JSON.stringify(item, null, 2);

    const rootElement = this.kernel.rootElement;
    rootElement.innerHTML = `
      <div class="raw-editor">
        <h2>Editing: ${this._escapeHtml(item.name || item.id)}</h2>
        <textarea id="raw-json" rows="30">${this._escapeHtml(json)}</textarea>
        <div class="actions">
          <button onclick="kernel.safeMode.saveItem('${itemId}')">Save</button>
          <button onclick="kernel.safeMode.render(kernel.rootElement)">Cancel</button>
        </div>
      </div>
    `;
  }

  async saveItem(itemId) {
    const textarea = document.getElementById("raw-json");
    if (!textarea) return;

    try {
      const updated = JSON.parse(textarea.value);
      updated.modified = Date.now();
      await this.kernel.storage.set(updated, this.kernel);
      this.kernel.moduleSystem.clearCache();
      alert("Saved successfully");
      this.render(this.kernel.rootElement);
    } catch (error) {
      alert(`Error: ${error.message}`);
    }
  }

  async deleteItem(itemId) {
    if (!confirm(`Delete item ${itemId}? This cannot be undone.`)) {
      return;
    }

    await this.kernel.storage.delete(itemId);
    await this.listAllItems();
  }

  async exportData() {
    const items = await this.kernel.storage.getAll();
    const json = JSON.stringify(items, null, 2);
    const blob = new Blob([json], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `safe-mode-backup-${Date.now()}.json`;
    a.click();
    URL.revokeObjectURL(url);
    alert(`Exported ${items.length} items`);
  }

  importData() {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = '.json';

    input.onchange = async (e) => {
      const file = e.target.files[0];
      if (!file) return;

      try {
        const text = await file.text();
        const items = JSON.parse(text);

        if (!Array.isArray(items)) {
          throw new Error('JSON must be an array of items');
        }

        let created = 0, skipped = 0;

        for (const item of items) {
          const exists = await this.kernel.storage.exists(item.id);
          if (!exists) {
            await this.kernel.storage.set(item, this.kernel);
            created++;
          } else {
            skipped++;
          }
        }

        // Clear module cache
        this.kernel.moduleSystem.clearCache();

        alert(`Import complete!\nCreated: ${created}\nSkipped: ${skipped}`);
        this.render(this.kernel.rootElement);

      } catch (error) {
        alert(`Import failed: ${error.message}`);
      }
    };

    input.click();
  }

  async resetSystem() {
    if (!confirm("WARNING: This will delete ALL your data!\n\nOnly the seed items will remain.\n\nHave you exported your data? This cannot be undone!")) {
      return;
    }

    const items = await this.kernel.storage.getAll();
    for (const item of items) {
      await this.kernel.storage.delete(item.id);
    }

    await this.kernel.ensureSeedItems();
    this.render(this.kernel.rootElement);
    alert("System reset complete");
  }

  _escapeHtml(str) {
    return String(str)
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;")
      .replace(/'/g, "&#039;");
  }
}

/* Minimal styling - intentionally basic, to be replaced from within */
* {
  box-sizing: border-box;
}

