  min-height: 0;
  overflow: hidden;
}

#repl-transcript {
  flex: 1;
  overflow-y: auto;
  padding: 20px;
}

.repl-transcript-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 15px;
}

.repl-transcript-header h4 {
  margin: 0;
  font-size: 14px;
  color: #666;
}

.repl-transcript-header button {
  padding: 4px 10px;
  font-size: 12px;
  cursor: pointer;
  border: 1px solid #ccc;
  background: white;
  border-radius: 4px;
}

.repl-transcript-header button:hover {
  background: #f0f0f0;
}

.repl-entry {
  margin-bottom: 15px;
  padding: 10px;
  background: #f8f8f8;
  border-radius: 4px;
  border-left: 3px solid #ccc;
}

.repl-entry.error {
